import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { Heart, ListPlus, Play, Pause, Music, CheckCircle2, Circle, X } from 'lucide-react';

const Home = () => {
  const [songs, setSongs] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  
  // --- States cho chức năng tạo Playlist mới ---
  const [isSelecting, setIsSelecting] = useState(false);
  const [newPlaylistTitle, setNewPlaylistTitle] = useState("");
  const [selectedSongIds, setSelectedSongIds] = useState([]);

  const audioRef = useRef(null);
  const navigate = useNavigate();
  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    fetchSongs();
  }, []);

  const fetchSongs = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/songs');
      setSongs(res.data);
    } catch (err) { console.error("Lỗi tải nhạc:", err); }
  };

  const handleLike = async (songId) => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    try {
      const res = await axios.post(`http://localhost:5000/api/songs/like/${songId}`, {
        userId: loggedInUser._id || loggedInUser.id
      });
      setSongs(songs.map(s => s._id === songId ? res.data : s));
    } catch (err) { console.error(err); }
  };

  const handleStartCreatePlaylist = () => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    const title = prompt("Nhập tên cho Playlist mới của bạn:");
    if (!title) return;
    
    setNewPlaylistTitle(title);
    setIsSelecting(true);
    setSelectedSongIds([]);
  };

  const toggleSongSelection = (songId) => {
    if (selectedSongIds.includes(songId)) {
      setSelectedSongIds(selectedSongIds.filter(id => id !== songId));
    } else {
      setSelectedSongIds([...selectedSongIds, songId]);
    }
  };

  const handleSavePlaylist = async () => {
    if (selectedSongIds.length === 0) {
      if (!window.confirm("Bạn chưa chọn bài hát nào. Vẫn muốn tạo playlist trống?")) return;
    }
    
    try {
      await axios.post('http://localhost:5000/api/songs/playlists', {
        title: newPlaylistTitle,
        userId: loggedInUser._id || loggedInUser.id,
        songIds: selectedSongIds
      });
      
      alert(`Thành công! Đã tạo playlist "${newPlaylistTitle}" với ${selectedSongIds.length} bài hát. 🎉`);
      setIsSelecting(false);
      setNewPlaylistTitle("");
      setSelectedSongIds([]);
    } catch (err) {
      alert("Lỗi khi lưu Playlist.");
    }
  };

  const playSong = (index) => {
    if (isSelecting) {
      toggleSongSelection(songs[index]._id);
      return;
    }
    setCurrentIndex(index);
    setIsPlaying(true);
  };

  const togglePlay = () => {
    if (isPlaying) audioRef.current.pause();
    else audioRef.current.play();
    setIsPlaying(!isPlaying);
  };

  return (
    <div style={{ padding: '30px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'Arial, sans-serif' }}>
      
      {/* THANH ĐIỀU KHIỂN CHỌN NHẠC */}
      {isSelecting && (
        <div style={selectionBarStyle}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
            <span style={{ fontSize: '18px' }}>
              Đang chọn nhạc cho: <b style={{ color: '#1db954' }}>{newPlaylistTitle}</b>
            </span>
            <span style={countBadge}>{selectedSongIds.length} bài đã chọn</span>
          </div>
          <div style={{ display: 'flex', gap: '15px' }}>
            <button onClick={handleSavePlaylist} style={btnSave}>HOÀN TẤT</button>
            <button onClick={() => setIsSelecting(false)} style={btnCancel} title="Hủy bỏ">
              <X size={20} />
            </button>
          </div>
        </div>
      )}

      {/* HEADER: Đã loại bỏ BXH và Hồ sơ */}
      {!isSelecting && (
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' }}>
          <h1 style={{ color: '#1db954', margin: 0, display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer' }} onClick={() => window.location.reload()}>
            <Music size={36} /> P2TUNES
          </h1>
          
          <div style={{ display: 'flex', gap: '15px' }}>
            {/* NÚT TẠO PLAYLIST: GIỮ NGUYÊN THIẾT KẾ CHỮ ĐEN ĐẬM */}
            <button onClick={handleStartCreatePlaylist} style={btnPrimary}>
              <ListPlus size={18} color="black" strokeWidth={3} /> TẠO PLAYLIST
            </button>
          </div>
        </div>
      )}

      {/* DANH SÁCH BÀI HÁT */}
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', 
        gap: '30px',
        marginTop: isSelecting ? '100px' : '0'
      }}>
        {songs.map((song, index) => {
          const isSelected = selectedSongIds.includes(song._id);
          return (
            <div 
              key={song._id} 
              style={{
                ...songCard, 
                border: isSelected ? '3px solid #1db954' : '3px solid transparent',
                transform: isSelected ? 'scale(1.02)' : 'scale(1)'
              }}
              onClick={() => playSong(index)}
            >
              <div style={{ position: 'relative' }}>
                <img src={`http://localhost:5000${song.imageUrl}`} alt={song.title} style={imgStyle} />
                
                {isSelecting ? (
                   <div style={checkIconContainer}>
                     {isSelected ? <CheckCircle2 color="#1db954" fill="white" size={32}/> : <Circle color="#ccc" size={32}/>}
                   </div>
                ) : (
                  <button onClick={(e) => { e.stopPropagation(); playSong(index); }} style={playOverlayBtn}>
                    <Play fill="white" size={20} />
                  </button>
                )}
              </div>
              
              <h3 style={{ margin: '15px 0 5px 0', fontSize: '17px', fontWeight: 'bold' }}>{song.title}</h3>
              <p style={{ color: '#666', fontSize: '14px', margin: '0 0 12px 0' }}>{song.artist}</p>
              
              {!isSelecting && (
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <button onClick={(e) => { e.stopPropagation(); handleLike(song._id); }} style={likeBtnStyle}>
                        <Heart 
                          size={20} 
                          fill={song.likes?.includes(loggedInUser?._id) ? "red" : "none"} 
                          color={song.likes?.includes(loggedInUser?._id) ? "red" : "#666"} 
                        />
                        <span style={{ fontWeight: 'bold' }}>{song.likes?.length || 0}</span>
                    </button>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* TRÌNH PHÁT NHẠC */}
      {currentIndex !== -1 && !isSelecting && (
        <div style={playerContainer}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '15px', width: '300px' }}>
            <img src={`http://localhost:5000${songs[currentIndex].imageUrl}`} style={{ width: '55px', height: '55px', borderRadius: '8px' }} alt="" />
            <div style={{ overflow: 'hidden' }}>
              <div style={{ fontWeight: 'bold', whiteSpace: 'nowrap', textOverflow: 'ellipsis', overflow: 'hidden' }}>{songs[currentIndex].title}</div>
              <div style={{ fontSize: '13px', color: '#888' }}>{songs[currentIndex].artist}</div>
            </div>
          </div>

          <div style={{ flex: 1, textAlign: 'center' }}>
            <button onClick={togglePlay} style={mainPlayBtn}>
              {isPlaying ? <Pause size={28} fill="white" /> : <Play size={28} fill="white" />}
            </button>
            <audio 
              ref={audioRef} 
              src={`http://localhost:5000${songs[currentIndex].songUrl}`} 
              autoPlay 
              onPlay={() => setIsPlaying(true)}
              onPause={() => setIsPlaying(false)}
            />
          </div>
          
          <div style={{ width: '300px' }}></div>
        </div>
      )}
    </div>
  );
};

/* --- STYLE OBJECTS --- */
const selectionBarStyle = {
    position: 'fixed', top: 0, left: 0, right: 0, height: '80px',
    backgroundColor: '#111', color: '#fff', display: 'flex',
    alignItems: 'center', justifyContent: 'space-between',
    padding: '0 60px', zIndex: 2000, borderBottom: '2px solid #1db954'
};

const countBadge = { background: '#333', padding: '5px 15px', borderRadius: '15px', fontSize: '14px', border: '1px solid #1db954' };
const btnSave = { background: '#1db954', color: 'white', border: 'none', padding: '12px 30px', borderRadius: '25px', fontWeight: 'bold', cursor: 'pointer', fontSize: '15px' };
const btnCancel = { background: '#f44336', color: 'white', border: 'none', width: '40px', height: '40px', borderRadius: '50%', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' };

const btnPrimary = { 
    background: '#ffffff', color: '#000000', border: '2px solid #000', 
    padding: '12px 24px', borderRadius: '30px', fontWeight: '900', 
    cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '10px', fontSize: '15px' 
};

const songCard = { 
    background: '#fff', padding: '18px', borderRadius: '20px', 
    boxShadow: '0 10px 25px rgba(0,0,0,0.06)', transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)', cursor: 'pointer' 
};

const imgStyle = { width: '100%', aspectRatio: '1/1', objectFit: 'cover', borderRadius: '12px' };
const playOverlayBtn = { 
    position: 'absolute', bottom: '12px', right: '12px', background: '#1db954', 
    border: 'none', borderRadius: '50%', width: '45px', height: '45px', 
    display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', color: 'white' 
};

const checkIconContainer = { position: 'absolute', top: '12px', right: '12px', filter: 'drop-shadow(0 4px 6px rgba(0,0,0,0.3))' };
const likeBtnStyle = { background: 'none', border: 'none', display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer', color: '#666' };
const playerContainer = { 
    position: 'fixed', bottom: 0, left: 0, right: 0, background: 'rgba(255,255,255,0.98)', 
    backdropFilter: 'blur(10px)', borderTop: '1px solid #eee', padding: '18px 60px', 
    display: 'flex', alignItems: 'center', justifyContent: 'space-between', zIndex: 1000 
};

const mainPlayBtn = { 
    background: '#1db954', color: 'white', border: 'none', width: '55px', height: '55px', 
    borderRadius: '50%', cursor: 'pointer', display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
    boxShadow: '0 4px 12px rgba(29, 185, 84, 0.4)'
};

export default Home;
